select s.*,c.receiptPath,tc.trainsClassId,tc.trainsClassName,ti.trainsId,ti.trainsTitle from studentinfo s left join studentcertificate c on c.studentId = s.id left join trainsclass tc on tc.trainsClassId = c.trainsClassId left join trainsinfo ti on ti.trainsId = tc.trainsInfoId
